module top_module(
  input clk,
  input reset,
  input load_data,
  input [31:0] in_data,
  output reg [31:0] shift_out,
  output reg [31:0] parallel_out
);reg [31:0] shift_reg;

  always @(posedge clk) begin
    if (reset) begin
      shift_reg <= 32'b0;
    end else if (load_data) begin
      shift_reg <= in_data;
    end else begin
      shift_reg <= {shift_reg[30:0], shift_reg[31]};
    end
  end

  assign shift_out = shift_reg;
  assign parallel_out = load_data ? in_data : shift_reg;

endmodule
